261	// create a (deep recursive) copy of a node use 'other' as target root node
262	void AstNode::cloneInto(AstNode &other) const
263	{
264		other.type = type;
265		other.str = str;
266		other.bits = bits;
267		other.is_input = is_input;
268		other.is_output = is_output;
269		other.is_reg = is_reg;
270		other.is_logic = is_logic;
271		other.is_signed = is_signed;
272		other.is_string = is_string;
273		other.is_wand = is_wand;
274		other.is_wor = is_wor;
275		other.range_valid = range_valid;
276		other.range_swapped = range_swapped;
277		other.was_checked = was_checked;
278		other.is_unsized = is_unsized;
279		other.is_custom_type = is_custom_type;
280		other.port_id = port_id,
281		other.range_left = range_left,
282		other.range_right = range_right;
283		other.integer = integer;
284		other.realvalue = realvalue;
285		other.is_enum = is_enum;
286		other.dimensions = dimensions;
287		other.unpacked_dimensions = unpacked_dimensions;
288		other.id2ast = id2ast;
289		other.basic_prep = basic_prep;
290		other.lookahead = lookahead;
291		other.location = location;
292		other.in_lvalue = in_lvalue;
293		other.in_param = in_param;
294		// Keep in_lvalue_from_above and in_param_from_above untouched
295	
296		other.delete_children();
297		for (auto& child : this->children)
298			other.children.push_back(child->clone());
299		for (auto& [key, val] : this->attributes)
300			other.attributes[key] = (val->clone());
301		 // fixup to set flags on cloned children
302		other.fixup_hierarchy_flags();
303	}
