319	// create a nice text representation of the node
320	// (traverse tree by recursion, use 'other' pointer for diffing two AST trees)
321	void AstNode::dumpAst(FILE *f, std::string indent) const
322	{
323		if (f == NULL) {
324			for (auto f : log_files)
325				dumpAst(f, indent);
326			return;
327		}
328	
329		std::string type_name = type2str(type);
330		fprintf(f, "%s%s <%s>", indent.c_str(), type_name.c_str(), loc_string().c_str());
331	
332		if (!flag_no_dump_ptr) {
333			if (id2ast)
334				fprintf(f, " [%p -> %p]", this, id2ast);
335			else
336				fprintf(f, " [%p]", this);
337		}
338	
339		if (!str.empty())
340			fprintf(f, " str='%s'", str.c_str());
341		if (!bits.empty()) {
342			fprintf(f, " bits='");
343			for (size_t i = bits.size(); i > 0; i--)
344				fprintf(f, "%c", bits[i-1] == State::S0 ? '0' :
345						bits[i-1] == State::S1 ? '1' :
346						bits[i-1] == RTLIL::Sx ? 'x' :
347						bits[i-1] == RTLIL::Sz ? 'z' : '?');
348			fprintf(f, "'(%d)", GetSize(bits));
349		}
350		if (is_input)
351			fprintf(f, " input");
352		if (is_output)
353			fprintf(f, " output");
354		if (is_logic)
355			fprintf(f, " logic");
356		if (is_reg) // this is an AST dump, not Verilog - if we see "logic reg" that's fine.
357			fprintf(f, " reg");
358		if (is_signed)
359			fprintf(f, " signed");
360		if (is_unsized)
361			fprintf(f, " unsized");
362		if (basic_prep)
363			fprintf(f, " basic_prep");
364		if (lookahead)
365			fprintf(f, " lookahead");
366		if (port_id > 0)
367			fprintf(f, " port=%d", port_id);
368		if (range_valid || range_left != -1 || range_right != 0)
369			fprintf(f, " %srange=[%d:%d]%s", range_swapped ? "swapped_" : "", range_left, range_right, range_valid ? "" : "!");
370		if (integer != 0)
371			fprintf(f, " int=%u", (int)integer);
372		if (realvalue != 0)
373			fprintf(f, " real=%e", realvalue);
374		if (!dimensions.empty()) {
375			fprintf(f, " dimensions=");
376			for (auto &dim : dimensions) {
377				int left = dim.range_right + dim.range_width - 1;
378				int right = dim.range_right;
379				if (dim.range_swapped)
380					std::swap(left, right);
381				fprintf(f, "[%d:%d]", left, right);
382			}
383		}
384		if (is_enum) {
385			fprintf(f, " type=enum");
386		}
387		if (in_lvalue)
388			fprintf(f, " in_lvalue");
389		if (in_param)
390			fprintf(f, " in_param");
391		fprintf(f, "\n");
392	
393		for (auto &it : attributes) {
394			fprintf(f, "%s  ATTR %s:\n", indent.c_str(), it.first.c_str());
395			it.second->dumpAst(f, indent + "    ");
396		}
397	
398		for (size_t i = 0; i < children.size(); i++)
399			children[i]->dumpAst(f, indent + "  ");
400	
401		fflush(f);
402	}
