404	// helper function for AstNode::dumpVlog()
405	static std::string id2vl(std::string txt)
406	{
407		if (txt.size() > 1 && txt[0] == '\\')
408			txt = txt.substr(1);
409		for (size_t i = 0; i < txt.size(); i++) {
410			if ('A' <= txt[i] && txt[i] <= 'Z') continue;
411			if ('a' <= txt[i] && txt[i] <= 'z') continue;
412			if ('0' <= txt[i] && txt[i] <= '9') continue;
413			if (txt[i] == '_') continue;
414			txt = "\\" + txt + " ";
415			break;
416		}
417		return txt;
418	}
419	
420	// dump AST node as Verilog pseudo-code
421	void AstNode::dumpVlog(FILE *f, std::string indent) const
422	{
423		bool first = true;
424		std::string txt;
425		std::vector<AstNode*> rem_children1, rem_children2;
426	
427		if (f == NULL) {
428			for (auto f : log_files)
429				dumpVlog(f, indent);
430			return;
431		}
432	
433		for (auto &it : attributes) {
434			fprintf(f, "%s" "(* %s = ", indent.c_str(), id2vl(it.first.str()).c_str());
435			it.second->dumpVlog(f, "");
436			fprintf(f, " *)%s", indent.empty() ? "" : "\n");
437		}
438	
439		switch (type)
440		{
441		case AST_MODULE:
442			fprintf(f, "%s" "module %s(", indent.c_str(), id2vl(str).c_str());
443			for (const auto& child : children)
444				if (child->type == AST_WIRE && (child->is_input || child->is_output)) {
445					fprintf(f, "%s%s", first ? "" : ", ", id2vl(child->str).c_str());
446					first = false;
447				}
448			fprintf(f, ");\n");
449	
450			for (const auto& child : children)
451				if (child->type == AST_PARAMETER || child->type == AST_LOCALPARAM || child->type == AST_DEFPARAM)
452					child->dumpVlog(f, indent + "  ");
453				else
454					rem_children1.push_back(child.get());
455	
456			for (auto child : rem_children1)
457				if (child->type == AST_WIRE || child->type == AST_AUTOWIRE || child->type == AST_MEMORY)
458					child->dumpVlog(f, indent + "  ");
459				else
460					rem_children2.push_back(child);
461			rem_children1.clear();
462	
463			for (auto child : rem_children2)
464				if (child->type == AST_TASK || child->type == AST_FUNCTION)
465					child->dumpVlog(f, indent + "  ");
466				else
467					rem_children1.push_back(child);
468			rem_children2.clear();
469	
470			for (auto child : rem_children1)
471				child->dumpVlog(f, indent + "  ");
472			rem_children1.clear();
473	
474			fprintf(f, "%s" "endmodule\n", indent.c_str());
475			break;
476	
477		case AST_WIRE:
478			if (is_input && is_output)
479				fprintf(f, "%s" "inout", indent.c_str());
480			else if (is_input)
481				fprintf(f, "%s" "input", indent.c_str());
482			else if (is_output)
483				fprintf(f, "%s" "output", indent.c_str());
484			else if (!is_reg)
485				fprintf(f, "%s" "wire", indent.c_str());
486			if (is_reg)
487				fprintf(f, "%s" "reg", (is_input || is_output) ? " " : indent.c_str());
488			if (is_signed)
489				fprintf(f, " signed");
490			for (const auto& child : children) {
491				fprintf(f, " ");
492				child->dumpVlog(f, "");
493			}
494			fprintf(f, " %s", id2vl(str).c_str());
495			fprintf(f, ";\n");
496			break;
497	
498		case AST_WIRETYPE:
499			fprintf(f, "%s", id2vl(str).c_str());
500			break;
501	
502		case AST_MEMORY:
503			fprintf(f, "%s" "memory", indent.c_str());
504			if (is_signed)
505				fprintf(f, " signed");
506			for (const auto& child : children) {
507				fprintf(f, " ");
508				child->dumpVlog(f, "");
509				if (first)
510					fprintf(f, " %s", id2vl(str).c_str());
511				first = false;
512			}
513			fprintf(f, ";\n");
514			break;
515	
516		if (0) { case AST_MEMRD:   txt = "@memrd@";  }
517		if (0) { case AST_MEMINIT: txt = "@meminit@";  }
518		if (0) { case AST_MEMWR:   txt = "@memwr@";  }
519			fprintf(f, "%s%s", indent.c_str(), txt.c_str());
520			for (const auto& child : children) {
521				fprintf(f, first ? "(" : ", ");
522				child->dumpVlog(f, "");
523				first = false;
524			}
525			fprintf(f, ")");
526			if (type != AST_MEMRD)
527				fprintf(f, ";\n");
528			break;
529	
530		case AST_RANGE:
531			if (range_valid) {
532				if (range_swapped)
533					fprintf(f, "[%d:%d]", range_right, range_left);
534				else
535					fprintf(f, "[%d:%d]", range_left, range_right);
536			} else {
537				for (const auto& child : children) {
538					fprintf(f, "%c", first ? '[' : ':');
539					child->dumpVlog(f, "");
540					first = false;
541				}
542				fprintf(f, "]");
543			}
544			break;
545	
546		case AST_MULTIRANGE:
547			for (const auto& child : children)
548				child->dumpVlog(f, "");
549			break;
550	
551		case AST_ALWAYS:
552			fprintf(f, "%s" "always @", indent.c_str());
553			for (const auto& child : children) {
554				if (child->type != AST_POSEDGE && child->type != AST_NEGEDGE && child->type != AST_EDGE)
555					continue;
556				fprintf(f, first ? "(" : ", ");
557				child->dumpVlog(f, "");
558				first = false;
559			}
560			fprintf(f, first ? "*\n" : ")\n");
561			for (const auto& child : children) {
562				if (child->type != AST_POSEDGE && child->type != AST_NEGEDGE && child->type != AST_EDGE)
563					child->dumpVlog(f, indent + "  ");
564			}
565			break;
566	
567		case AST_INITIAL:
568			fprintf(f, "%s" "initial\n", indent.c_str());
569			for (const auto& child : children) {
570				if (child->type != AST_POSEDGE && child->type != AST_NEGEDGE && child->type != AST_EDGE)
571					child->dumpVlog(f, indent + "  ");
572			}
573			break;
574	
575		case AST_POSEDGE:
576		case AST_NEGEDGE:
577		case AST_EDGE:
578			if (type == AST_POSEDGE)
579				fprintf(f, "posedge ");
580			if (type == AST_NEGEDGE)
581				fprintf(f, "negedge ");
582			for (const auto& child : children)
583				child->dumpVlog(f, "");
584			break;
585	
586		case AST_IDENTIFIER:
587			{
588				AstNode *member_node = get_struct_member();
589				if (member_node)
590					fprintf(f, "%s[%d:%d]", id2vl(str).c_str(), member_node->range_left, member_node->range_right);
591				else
592					fprintf(f, "%s", id2vl(str).c_str());
593			}
594			for (const auto& child : children)
595				child->dumpVlog(f, "");
596			break;
597	
598		case AST_STRUCT:
599		case AST_UNION:
600		case AST_STRUCT_ITEM:
601			fprintf(f, "%s", id2vl(str).c_str());
602			break;
603	
604		case AST_CONSTANT:
605			if (!str.empty())
606				fprintf(f, "\"%s\"", str.c_str());
607			else if (bits.size() == 32)
608				fprintf(f, "%d", RTLIL::Const(bits).as_int());
609			else
610				fprintf(f, "%d'b %s", GetSize(bits), RTLIL::Const(bits).as_string().c_str());
611			break;
612	
613		case AST_REALVALUE:
614			fprintf(f, "%e", realvalue);
615			break;
616	
617		case AST_BLOCK:
618			if (children.size() == 1) {
619				children[0]->dumpVlog(f, indent);
620			} else {
621				fprintf(f, "%s" "begin\n", indent.c_str());
622				for (const auto& child : children)
623					child->dumpVlog(f, indent + "  ");
624				fprintf(f, "%s" "end\n", indent.c_str());
625			}
626			break;
627	
628		case AST_CASE:
629			if (children.size() > 1 && children[1]->type == AST_CONDX)
630				fprintf(f, "%s" "casex (", indent.c_str());
631			else if (children.size() > 1 && children[1]->type == AST_CONDZ)
632				fprintf(f, "%s" "casez (", indent.c_str());
633			else
634				fprintf(f, "%s" "case (", indent.c_str());
635			children[0]->dumpVlog(f, "");
636			fprintf(f, ")\n");
637			for (size_t i = 1; i < children.size(); i++) {
638				const auto& child = children[i];
639				child->dumpVlog(f, indent + "  ");
640			}
641			fprintf(f, "%s" "endcase\n", indent.c_str());
642			break;
643	
644		case AST_COND:
645		case AST_CONDX:
646		case AST_CONDZ:
647			for (const auto& child : children) {
648				if (child->type == AST_BLOCK) {
649					fprintf(f, ":\n");
650					child->dumpVlog(f, indent + "  ");
651					first = true;
652				} else {
653					fprintf(f, "%s", first ? indent.c_str() : ", ");
654					if (child->type == AST_DEFAULT)
655						fprintf(f, "default");
656					else
657						child->dumpVlog(f, "");
658					first = false;
659				}
660			}
661			break;
662	
663		case AST_ASSIGN:
664			fprintf(f, "%sassign ", indent.c_str());
665			children[0]->dumpVlog(f, "");
666			fprintf(f, " = ");
667			children[1]->dumpVlog(f, "");
668			fprintf(f, ";\n");
669			break;
670	
671		case AST_ASSIGN_EQ:
672		case AST_ASSIGN_LE:
673			fprintf(f, "%s", indent.c_str());
674			children[0]->dumpVlog(f, "");
675			fprintf(f, " %s ", type == AST_ASSIGN_EQ ? "=" : "<=");
676			children[1]->dumpVlog(f, "");
677			fprintf(f, ";\n");
678			break;
679	
680		case AST_CONCAT:
681			fprintf(f, "{");
682			for (int i = GetSize(children)-1; i >= 0; i--) {
683				const auto& child = children[i];
684				if (!first)
685					fprintf(f, ", ");
686				child->dumpVlog(f, "");
687				first = false;
688			}
689			fprintf(f, "}");
690			break;
691	
692		case AST_REPLICATE:
693			fprintf(f, "{");
694			children[0]->dumpVlog(f, "");
695			fprintf(f, "{");
696			children[1]->dumpVlog(f, "");
697			fprintf(f, "}}");
698			break;
699	
700		case AST_ASSIGN_PATTERN:
701			fprintf(f, "'{");
702			for (int i = 0; i < GetSize(children); i++) {
703				if (i != 0)
704					fprintf(f, ", ");
705				children[i]->dumpVlog(f, "");
706			}
707			fprintf(f, "}");
708			break;
709	
710		if (0) { case AST_BIT_NOT:     txt = "~";  }
711		if (0) { case AST_REDUCE_AND:  txt = "&";  }
712		if (0) { case AST_REDUCE_OR:   txt = "|";  }
713		if (0) { case AST_REDUCE_XOR:  txt = "^";  }
714		if (0) { case AST_REDUCE_XNOR: txt = "~^"; }
715		if (0) { case AST_REDUCE_BOOL: txt = "|";  }
716		if (0) { case AST_POS:         txt = "+";  }
717		if (0) { case AST_NEG:         txt = "-";  }
718		if (0) { case AST_LOGIC_NOT:   txt = "!";  }
719		if (0) { case AST_SELFSZ:      txt = "@selfsz@";  }
720		if (0) { case AST_TO_SIGNED:   txt = "signed'";  }
721		if (0) { case AST_TO_UNSIGNED: txt = "unsigned'";  }
722			fprintf(f, "%s(", txt.c_str());
723			children[0]->dumpVlog(f, "");
724			fprintf(f, ")");
725			break;
726	
727		case AST_CAST_SIZE:
728			switch (children[0]->type)
729			{
730			case AST_WIRE:
731				if (children[0]->children.size() > 0)
732					children[0]->children[0]->dumpVlog(f, "");
733				else
734					fprintf(f, "%d'", children[0]->range_left - children[0]->range_right + 1);
735				break;
736			default:
737				children[0]->dumpVlog(f, "");
738			}
739			fprintf(f, "'(");
740			children[1]->dumpVlog(f, "");
741			fprintf(f, ")");
742			break;
743	
744		if (0) { case AST_BIT_AND:      txt = "&";   }
745		if (0) { case AST_BIT_OR:       txt = "|";   }
746		if (0) { case AST_BIT_XOR:      txt = "^";   }
747		if (0) { case AST_BIT_XNOR:     txt = "~^";  }
748		if (0) { case AST_SHIFT_LEFT:   txt = "<<";  }
749		if (0) { case AST_SHIFT_RIGHT:  txt = ">>";  }
750		if (0) { case AST_SHIFT_SLEFT:  txt = "<<<"; }
751		if (0) { case AST_SHIFT_SRIGHT: txt = ">>>"; }
752		if (0) { case AST_SHIFTX:       txt = "@shiftx@"; }
753		if (0) { case AST_SHIFT:        txt = "@shift@"; }
754		if (0) { case AST_LT:           txt = "<";   }
755		if (0) { case AST_LE:           txt = "<=";  }
756		if (0) { case AST_EQ:           txt = "==";  }
757		if (0) { case AST_NE:           txt = "!=";  }
758		if (0) { case AST_EQX:          txt = "===";  }
759		if (0) { case AST_NEX:          txt = "!==";  }
760		if (0) { case AST_GE:           txt = ">=";  }
761		if (0) { case AST_GT:           txt = ">";   }
762		if (0) { case AST_ADD:          txt = "+";   }
763		if (0) { case AST_SUB:          txt = "-";   }
764		if (0) { case AST_MUL:          txt = "*";   }
765		if (0) { case AST_DIV:          txt = "/";   }
766		if (0) { case AST_MOD:          txt = "%";   }
767		if (0) { case AST_POW:          txt = "**";  }
768		if (0) { case AST_LOGIC_AND:    txt = "&&";  }
769		if (0) { case AST_LOGIC_OR:     txt = "||";  }
770			fprintf(f, "(");
771			children[0]->dumpVlog(f, "");
772			fprintf(f, ")%s(", txt.c_str());
773			children[1]->dumpVlog(f, "");
774			fprintf(f, ")");
775			break;
776	
777		case AST_TERNARY:
778			fprintf(f, "(");
779			children[0]->dumpVlog(f, "");
780			fprintf(f, ") ? (");
781			children[1]->dumpVlog(f, "");
782			fprintf(f, ") : (");
783			children[2]->dumpVlog(f, "");
784			fprintf(f, ")");
785			break;
786	
787		default:
788			std::string type_name = type2str(type);
789			fprintf(f, "%s" "/** %s **/%s", indent.c_str(), type_name.c_str(), indent.empty() ? "" : "\n");
790			// dumpAst(f, indent, NULL);
791		}
792	
793		fflush(f);
794	}
