796	// check if two AST nodes are identical
797	bool AstNode::operator==(const AstNode &other) const
798	{
799		if (type != other.type)
800			return false;
801		if (children.size() != other.children.size())
802			return false;
803		if (str != other.str)
804			return false;
805		if (bits != other.bits)
806			return false;
807		if (is_input != other.is_input)
808			return false;
809		if (is_output != other.is_output)
810			return false;
811		if (is_logic != other.is_logic)
812			return false;
813		if (is_reg != other.is_reg)
814			return false;
815		if (is_signed != other.is_signed)
816			return false;
817		if (is_string != other.is_string)
818			return false;
819		if (range_valid != other.range_valid)
820			return false;
821		if (range_swapped != other.range_swapped)
822			return false;
823		if (port_id != other.port_id)
824			return false;
825		if (range_left != other.range_left)
826			return false;
827		if (range_right != other.range_right)
828			return false;
829		if (integer != other.integer)
830			return false;
831		for (size_t i = 0; i < children.size(); i++)
832			if (*children[i] != *other.children[i])
833				return false;
834		return true;
835	}
