854	// create an AST node for a constant (using a 32 bit int as value)
855	std::unique_ptr<AstNode> AstNode::mkconst_int(AstSrcLocType loc, uint32_t v, bool is_signed, int width)
856	{
857		auto node = std::make_unique<AstNode>(loc, AST_CONSTANT);
858		node->integer = v;
859		node->is_signed = is_signed;
860		for (int i = 0; i < width; i++) {
861			node->bits.push_back((v & 1) ? State::S1 : State::S0);
862			v = v >> 1;
863		}
864		node->range_valid = true;
865		node->range_left = width-1;
866		node->range_right = 0;
867		return node;
868	}
