870	// create an AST node for a constant (using a bit vector as value)
871	std::unique_ptr<AstNode> AstNode::mkconst_bits(AstSrcLocType loc, const std::vector<RTLIL::State> &v, bool is_signed, bool is_unsized)
872	{
873		auto node = std::make_unique<AstNode>(loc, AST_CONSTANT);
874		node->is_signed = is_signed;
875		node->bits = v;
876		for (size_t i = 0; i < 32; i++) {
877			if (i < node->bits.size())
878				node->integer |= (node->bits[i] == State::S1) << i;
879			else if (is_signed && !node->bits.empty())
880				node->integer |= (node->bits.back() == State::S1) << i;
881		}
882		node->range_valid = true;
883		node->range_left = node->bits.size()-1;
884		node->range_right = 0;
885		node->is_unsized = is_unsized;
886		return node;
887	}
