894	// create an AST node for a constant (using a string in bit vector form as value)
895	std::unique_ptr<AstNode> AstNode::mkconst_str(AstSrcLocType loc, const std::vector<RTLIL::State> &v)
896	{
897		auto node = mkconst_str(loc, RTLIL::Const(v).decode_string());
898		while (GetSize(node->bits) < GetSize(v))
899			node->bits.push_back(RTLIL::State::S0);
900		log_assert(node->bits == v);
901		return node;
902	}
