904	// create an AST node for a constant (using a string as value)
905	std::unique_ptr<AstNode> AstNode::mkconst_str(AstSrcLocType loc, const std::string &str)
906	{
907		std::unique_ptr<AstNode> node;
908	
909		// LRM 1364-2005 5.2.3.3 The empty string literal ("") shall be considered
910		// equivalent to the ASCII NUL ("\0")
911		if (str.empty()) {
912			node = AstNode::mkconst_int(loc, 0, false, 8);
913		} else {
914			std::vector<RTLIL::State> data;
915			data.reserve(str.size() * 8);
916			for (size_t i = 0; i < str.size(); i++) {
917				unsigned char ch = str[str.size() - i - 1];
918				for (int j = 0; j < 8; j++) {
919					data.push_back((ch & 1) ? State::S1 : State::S0);
920					ch = ch >> 1;
921				}
922			}
923			node = AstNode::mkconst_bits(loc, data, false);
924		}
925	
926		node->is_string = true;
927		node->str = str;
928		return node;
929	}
