931	// create a temporary register
932	std::unique_ptr<AstNode> AstNode::mktemp_logic(AstSrcLocType loc, const std::string &name, AstNode *mod, bool nosync, int range_left, int range_right, bool is_signed)
933	{
934		auto wire_owned = std::make_unique<AstNode>(loc, AST_WIRE, std::make_unique<AstNode>(loc, AST_RANGE, mkconst_int(loc, range_left, true), mkconst_int(loc, range_right, true)));
935		auto* wire = wire_owned.get();
936		wire->str = stringf("%s%s:%d$%d", name, RTLIL::encode_filename(*location.begin.filename), location.begin.line, autoidx++);
937		if (nosync)
938			wire->set_attribute(ID::nosync, AstNode::mkconst_int(loc, 1, false));
939		wire->is_signed = is_signed;
940		wire->is_logic = true;
941		mod->children.push_back(std::move(wire_owned));
942		while (wire->simplify(true, 1, -1, false)) { }
943	
944		auto ident = std::make_unique<AstNode>(loc, AST_IDENTIFIER);
945		ident->str = wire->str;
946		ident->id2ast = wire;
947	
948		return ident;
949	}
