1030	uint64_t AstNode::asInt(bool is_signed)
1031	{
1032		if (type == AST_CONSTANT)
1033		{
1034			RTLIL::Const v = bitsAsConst(64, is_signed);
1035			uint64_t ret = 0;
1036	
1037			for (int i = 0; i < 64; i++)
1038				if (v.at(i) == RTLIL::State::S1)
1039					ret |= uint64_t(1) << i;
1040	
1041			return ret;
1042		}
1043	
1044		if (type == AST_REALVALUE)
1045			return uint64_t(realvalue);
1046	
1047		log_abort();
