1049	
1050	double AstNode::asReal(bool is_signed)
1051	{
1052		if (type == AST_CONSTANT)
1053		{
1054			RTLIL::Const val(bits);
1055	
1056			bool is_negative = is_signed && !val.empty() && val.back() == RTLIL::State::S1;
1057			if (is_negative)
1058				val = const_neg(val, val, false, false, val.size());
1059	
1060			double v = 0;
1061			for (auto i = 0; i < val.size(); i++)
1062				// IEEE Std 1800-2012 Par 6.12.2: Individual bits that are x or z in
1063				// the net or the variable shall be treated as zero upon conversion.
1064				if (val.at(i) == RTLIL::State::S1)
1065					v += exp2(i);
1066			if (is_negative)
1067				v *= -1;
1068	
1069			return v;
1070		}
1071	
1072		if (type == AST_REALVALUE)
1073			return realvalue;
1074	
1075		log_abort();
1076	}
1077	
1078	RTLIL::Const AstNode::realAsConst(int width)
1079	{
1080		double v = round(realvalue);
1081		RTLIL::Const result;
1082		if (!std::isfinite(v)) {
1083			result = std::vector<RTLIL::State>(width, RTLIL::State::Sx);
1084		} else {
1085			bool is_negative = v < 0;
1086			if (is_negative)
1087				v *= -1;
1088			RTLIL::Const::Builder b(width);
1089			for (int i = 0; i < width; i++, v /= 2)
1090				b.push_back((fmod(floor(v), 2) != 0) ? RTLIL::State::S1 : RTLIL::State::S0);
1091			result = b.build();
1092			if (is_negative)
1093				result = const_neg(result, result, false, false, result.size());
1094		}
1095		return result;
1096	}
