1108	static bool param_has_no_default(const AstNode* param) {
1109		const auto &children = param->children;
1110		log_assert(param->type == AST_PARAMETER);
1111		log_assert(children.size() <= 2);
1112		return children.empty() ||
1113			(children.size() == 1 && children[0]->type == AST_RANGE);
