1115	
1116	static RTLIL::Module *process_module(RTLIL::Design *design, AstNode *ast, bool defer, std::unique_ptr<AstNode> original_ast = NULL, bool quiet = false)
1117	{
1118		log_assert(current_scope.empty());
1119		log_assert(ast->type == AST_MODULE || ast->type == AST_INTERFACE);
1120	
1121		if (defer)
1122			log("Storing AST representation for module `%s'.\n", ast->str);
1123		else if (!quiet) {
1124			log("Generating RTLIL representation for module `%s'.\n", ast->str);
1125		}
1126	
1127		AstModule *module = new AstModule;
1128		current_module = module;
1129	
1130		module->ast = nullptr;
1131		module->name = ast->str;
1132		set_src_attr(module, ast);
1133		module->set_bool_attribute(ID::cells_not_processed);
1134	
1135		current_ast_mod = ast;
1136		std::unique_ptr<AstNode> ast_before_simplify;
1137		if (original_ast != NULL)
1138			ast_before_simplify = std::move(original_ast);
1139		else
1140			ast_before_simplify = ast->clone();
1141	
1142		if (flag_dump_ast1) {
1143			log("Dumping AST before simplification:\n");
1144			ast->dumpAst(NULL, "    ");
1145			log("--- END OF AST DUMP ---\n");
1146		}
1147		if (flag_dump_vlog1) {
1148			log("Dumping Verilog AST before simplification:\n");
1149			ast->dumpVlog(NULL, "    ");
1150			log("--- END OF AST DUMP ---\n");
1151		}
1152	
1153		if (!defer)
1154		{
1155			for (auto& node : ast->children)
1156				if (node->type == AST_PARAMETER && param_has_no_default(node.get()))
1157					node->input_error("Parameter `%s' has no default value and has not been overridden!\n", node->str);
1158	
1159			bool blackbox_module = flag_lib;
1160	
1161			if (!blackbox_module && !flag_noblackbox) {
1162				blackbox_module = true;
1163				for (const auto& child : ast->children) {
1164					if (child->type == AST_WIRE && (child->is_input || child->is_output))
1165						continue;
1166					if (child->type == AST_PARAMETER || child->type == AST_LOCALPARAM)
1167						continue;
1168					if (child->type == AST_CELL && child->children.size() > 0 && child->children[0]->type == AST_CELLTYPE &&
1169							(child->children[0]->str == "$specify2" || child->children[0]->str == "$specify3" || child->children[0]->str == "$specrule"))
1170						continue;
1171					blackbox_module = false;
1172					break;
1173				}
1174			}
1175	
1176			// simplify this module or interface using the current design as context
1177			// for lookup up ports and wires within cells
1178			set_simplify_design_context(design);
1179			while (ast->simplify(!flag_noopt, 0, -1, false)) { }
1180			set_simplify_design_context(nullptr);
1181	
1182			if (flag_dump_ast2) {
1183				log("Dumping AST after simplification:\n");
1184				ast->dumpAst(NULL, "    ");
1185				log("--- END OF AST DUMP ---\n");
1186			}
1187	
1188			if (flag_dump_vlog2) {
1189				log("Dumping Verilog AST after simplification:\n");
1190				ast->dumpVlog(NULL, "    ");
1191				log("--- END OF AST DUMP ---\n");
1192			}
1193			for (auto &attr: ast->attributes)
1194				log_assert((bool)attr.second.get());
1195			if (flag_nowb && ast->attributes.count(ID::whitebox)) {
1196				ast->attributes.erase(ID::whitebox);
1197			}
1198			for (auto &attr: ast->attributes)
1199				log_assert((bool)attr.second.get());
1200			if (ast->attributes.count(ID::lib_whitebox)) {
1201				if (flag_lib && !flag_nowb) {
1202					ast->attributes[ID::whitebox] = std::move(
1203						ast->attributes[ID::lib_whitebox]
1204					);
1205				}
1206				ast->attributes.erase(ID::lib_whitebox);
1207			}
1208			for (auto &attr: ast->attributes)
1209				log_assert((bool)attr.second.get());
1210	
1211			if (!blackbox_module && ast->attributes.count(ID::blackbox)) {
1212				auto& n = ast->attributes.at(ID::blackbox);
1213				if (n->type != AST_CONSTANT)
1214					ast->input_error("Got blackbox attribute with non-constant value!\n");
1215				blackbox_module = n->asBool();
1216			}
1217	
1218			if (blackbox_module && ast->attributes.count(ID::whitebox)) {
1219				auto& n = ast->attributes.at(ID::whitebox);
1220				if (n->type != AST_CONSTANT)
1221					ast->input_error("Got whitebox attribute with non-constant value!\n");
1222				blackbox_module = !n->asBool();
1223			}
1224	
1225			if (ast->attributes.count(ID::noblackbox)) {
1226				if (blackbox_module) {
1227					auto& n = ast->attributes.at(ID::noblackbox);
1228					if (n->type != AST_CONSTANT)
1229						ast->input_error("Got noblackbox attribute with non-constant value!\n");
1230					blackbox_module = !n->asBool();
1231				}
1232				ast->attributes.erase(ID::noblackbox);
1233			}
1234			for (auto &attr: ast->attributes)
1235				log_assert((bool)attr.second.get());
1236			if (blackbox_module)
1237			{
1238				if (ast->attributes.count(ID::whitebox)) {
1239					ast->attributes.erase(ID::whitebox);
1240				}
1241	
1242				if (ast->attributes.count(ID::lib_whitebox)) {
1243					ast->attributes.erase(ID::lib_whitebox);
1244				}
1245	
1246				std::vector<std::unique_ptr<AstNode>> new_children;
1247				for (auto& child : ast->children) {
1248					if (child->type == AST_WIRE && (child->is_input || child->is_output)) {
1249						new_children.push_back(std::move(child));
1250					} else if (child->type == AST_PARAMETER) {
1251						new_children.push_back(std::move(child));
1252					} else if (child->type == AST_CELL && child->children.size() > 0 && child->children[0]->type == AST_CELLTYPE &&
1253							(child->children[0]->str == "$specify2" || child->children[0]->str == "$specify3" || child->children[0]->str == "$specrule")) {
1254						new_children.push_back(std::move(child));
1255					}
1256				}
1257	
1258				ast->children.swap(new_children);
1259	
1260				if (ast->attributes.count(ID::blackbox) == 0) {
1261					ast->set_attribute(ID::blackbox, AstNode::mkconst_int(ast->location, 1, false));
1262				}
1263			}
1264	
1265			ignoreThisSignalsInInitial = RTLIL::SigSpec();
1266	
1267			for (auto &attr : ast->attributes) {
1268				log_assert((bool)attr.second.get());
1269				if (attr.second->type != AST_CONSTANT)
1270					ast->input_error("Attribute `%s' with non-constant value!\n", attr.first);
1271				module->attributes[attr.first] = attr.second->asAttrConst();
1272			}
1273			for (size_t i = 0; i < ast->children.size(); i++) {
1274				const auto& node = ast->children[i];
1275				if (node->type == AST_WIRE || node->type == AST_MEMORY)
1276					node->genRTLIL();
1277			}
1278			for (size_t i = 0; i < ast->children.size(); i++) {
1279				const auto& node = ast->children[i];
1280				if (node->type != AST_WIRE && node->type != AST_MEMORY && node->type != AST_INITIAL)
1281					node->genRTLIL();
1282			}
1283	
1284			ignoreThisSignalsInInitial.sort_and_unify();
1285	
1286			for (size_t i = 0; i < ast->children.size(); i++) {
1287				const auto& node = ast->children[i];
1288				if (node->type == AST_INITIAL)
1289					node->genRTLIL();
1290			}
1291	
1292			ignoreThisSignalsInInitial = RTLIL::SigSpec();
1293			current_scope.clear();
1294		}
1295		else {
1296			for (auto &attr : ast->attributes) {
1297				if (attr.second->type != AST_CONSTANT)
1298					continue;
1299				module->attributes[attr.first] = attr.second->asAttrConst();
1300			}
1301			for (const auto& node : ast->children)
1302				if (node->type == AST_PARAMETER)
1303					current_module->avail_parameters(node->str);
1304		}
1305	
1306		if (ast->type == AST_INTERFACE)
1307			module->set_bool_attribute(ID::is_interface);
1308		module->ast = std::move(ast_before_simplify);
1309		module->nolatches = flag_nolatches;
1310		module->nomeminit = flag_nomeminit;
1311		module->nomem2reg = flag_nomem2reg;
1312		module->mem2reg = flag_mem2reg;
1313		module->noblackbox = flag_noblackbox;
1314		module->lib = flag_lib;
1315		module->nowb = flag_nowb;
1316		module->noopt = flag_noopt;
1317		module->icells = flag_icells;
1318		module->pwires = flag_pwires;
1319		module->autowire = flag_autowire;
1320		module->fixup_ports();
1321	
1322		if (flag_dump_rtlil) {
1323			log("Dumping generated RTLIL:\n");
1324			log_module(module);
1325			log("--- END OF RTLIL DUMP ---\n");
1326		}
1327	
1328		design->add(current_module);
1329		return current_module;
1330	}
