1332	RTLIL::Module *
1333	AST_INTERNAL::process_and_replace_module(RTLIL::Design *design,
1334	                                         RTLIL::Module *old_module,
1335	                                         AST::AstNode *new_ast,
1336	                                         std::unique_ptr<AstNode> original_ast)
1337	{
1338		// The old module will be deleted. Rename and mark for deletion, using
1339		// a static counter to make sure we get a unique name.
1340		static unsigned counter;
1341		std::ostringstream new_name;
1342		new_name << old_module->name.str()
1343			 << "_before_process_and_replace_module_"
1344			 << counter;
1345		++counter;
1346	
1347		design->rename(old_module, new_name.str());
1348		old_module->set_bool_attribute(ID::to_delete);
1349	
1350		// Check if the module was the top module. If it was, we need to remove
1351		// the top attribute and put it on the new module.
1352		bool is_top = false;
1353		if (old_module->get_bool_attribute(ID::initial_top)) {
1354			old_module->attributes.erase(ID::initial_top);
1355			is_top = true;
1356		}
1357	
1358		// Generate RTLIL from AST for the new module and add to the design:
1359		RTLIL::Module* new_module = process_module(design, new_ast, false, std::move(original_ast));
1360	
1361		if (is_top)
1362			new_module->set_bool_attribute(ID::top);
1363	
1364		return new_module;
1365	}
