1367	// renames identifiers in tasks and functions within a package
1368	static void rename_in_package_stmts(AstNode *pkg)
1369	{
1370		std::unordered_set<std::string> idents;
1371		for (auto& item : pkg->children)
1372			idents.insert(item->str);
1373		std::function<void(std::unique_ptr<AstNode>&)> rename =
1374			[&rename, &idents, pkg](std::unique_ptr<AstNode>& node) {
1375				for (auto& child : node->children) {
1376					if (idents.count(child->str))
1377						child->str = pkg->str + "::" + child->str.substr(1);
1378					rename(child);
1379				}
1380		};
1381		for (auto& item : pkg->children)
1382			if (item->type == AST_FUNCTION || item->type == AST_TASK)
1383				rename(item);
1384	}
