1386	// create AstModule instances for all modules in the AST tree and add them to 'design'
1387	void AST::process(RTLIL::Design *design, AstNode *ast, bool nodisplay, bool dump_ast1, bool dump_ast2, bool no_dump_ptr, bool dump_vlog1, bool dump_vlog2, bool dump_rtlil,
1388			bool nolatches, bool nomeminit, bool nomem2reg, bool mem2reg, bool noblackbox, bool lib, bool nowb, bool noopt, bool icells, bool pwires, bool nooverwrite, bool overwrite, bool defer, bool autowire)
1389	{
1390		current_ast = ast;
1391		current_ast_mod = nullptr;
1392		flag_nodisplay = nodisplay;
1393		flag_dump_ast1 = dump_ast1;
1394		flag_dump_ast2 = dump_ast2;
1395		flag_no_dump_ptr = no_dump_ptr;
1396		flag_dump_vlog1 = dump_vlog1;
1397		flag_dump_vlog2 = dump_vlog2;
1398		flag_dump_rtlil = dump_rtlil;
1399		flag_nolatches = nolatches;
1400		flag_nomeminit = nomeminit;
1401		flag_nomem2reg = nomem2reg;
1402		flag_mem2reg = mem2reg;
1403		flag_noblackbox = noblackbox;
1404		flag_lib = lib;
1405		flag_nowb = nowb;
1406		flag_noopt = noopt;
1407		flag_icells = icells;
1408		flag_pwires = pwires;
1409		flag_autowire = autowire;
1410	
1411		ast->fixup_hierarchy_flags(true);
1412	
1413		log_assert(current_ast->type == AST_DESIGN);
1414		for (const auto& child : current_ast->children)
1415		{
1416			if (child->type == AST_MODULE || child->type == AST_INTERFACE)
1417			{
1418				for (auto& n : design->verilog_globals)
1419					child->children.push_back(n->clone());
1420	
1421				// append nodes from previous packages using package-qualified names
1422				for (auto& n : design->verilog_packages) {
1423					for (auto &o : n->children) {
1424						auto cloned_node = o->clone();
1425						// log("cloned node %s\n", type2str(cloned_node->type));
1426						if (cloned_node->type == AST_ENUM) {
1427							for (auto &e : cloned_node->children) {
1428								log_assert(e->type == AST_ENUM_ITEM);
1429								e->str = n->str + std::string("::") + e->str.substr(1);
1430							}
1431						} else {
1432							cloned_node->str = n->str + std::string("::") + cloned_node->str.substr(1);
1433						}
1434						child->children.push_back(std::move(cloned_node));
1435					}
1436				}
1437	
1438				if (flag_icells && child->str.compare(0, 2, "\\$") == 0)
1439					child->str = child->str.substr(1);
1440	
1441				bool defer_local = defer;
1442				if (!defer_local)
1443					for (const auto& node : child->children)
1444						if (node->type == AST_PARAMETER && param_has_no_default(node.get()))
1445						{
1446							log("Deferring `%s' because it contains parameter(s) without defaults.\n", child->str);
1447							defer_local = true;
1448							break;
1449						}
1450	
1451	
1452				if (defer_local)
1453					child->str = "$abstract" + child->str;
1454	
1455				if (design->has(child->str)) {
1456					RTLIL::Module *existing_mod = design->module(child->str);
1457					if (!nooverwrite && !overwrite && !existing_mod->get_blackbox_attribute()) {
1458						log_file_error(*child->location.begin.filename, child->location.begin.line, "Re-definition of module `%s'!\n", child->str);
1459					} else if (nooverwrite) {
1460						log("Ignoring re-definition of module `%s' at %s.\n",
1461								child->str.c_str(), child->loc_string().c_str());
1462						continue;
1463					} else {
1464						log("Replacing existing%s module `%s' at %s.\n",
1465								existing_mod->get_bool_attribute(ID::blackbox) ? " blackbox" : "",
1466								child->str.c_str(), child->loc_string().c_str());
1467						design->remove(existing_mod);
1468					}
1469				}
1470	
1471				process_module(design, child.get(), defer_local);
1472				current_ast_mod = nullptr;
1473			}
1474			else if (child->type == AST_PACKAGE) {
1475				// process enum/other declarations
1476				child->simplify(true, 1, -1, false);
1477				rename_in_package_stmts(child.get());
1478				design->verilog_packages.push_back(child->clone());
1479				current_scope.clear();
1480			}
1481			else if (child->type == AST_BIND) {
1482				// top-level bind construct
1483				for (RTLIL::Binding *binding : child->genBindings())
1484					design->add(binding);
1485			}
1486			else {
1487				// must be global definition
1488				if (child->type == AST_PARAMETER)
1489					child->type = AST_LOCALPARAM; // cannot be overridden
1490				design->verilog_globals.push_back(child->clone());
1491				current_scope.clear();
1492			}
1493		}
1494	
1495	}
