1497	// An interface port with modport is specified like this:
1498	//    <interface_name>.<modport_name>
1499	// This function splits the interface_name from the modport_name, and fails if it is not a valid combination
1500	std::pair<std::string,std::string> AST::split_modport_from_type(std::string name_type)
1501	{
1502		std::string interface_type = "";
1503		std::string interface_modport = "";
1504		size_t ndots = std::count(name_type.begin(), name_type.end(), '.');
1505		// Separate the interface instance name from any modports:
1506		if (ndots == 0) { // Does not have modport
1507			interface_type = name_type;
1508		}
1509		else {
1510			std::stringstream name_type_stream(name_type);
1511			std::string segment;
1512			std::vector<std::string> seglist;
1513			while(std::getline(name_type_stream, segment, '.')) {
1514				seglist.push_back(segment);
1515			}
1516			if (ndots == 1) { // Has modport
1517				interface_type = seglist[0];
1518				interface_modport = seglist[1];
1519			}
1520			else { // Erroneous port type
1521				log_error("More than two '.' in signal port type (%s)\n", name_type);
1522			}
1523		}
1524		return std::pair<std::string,std::string>(interface_type, interface_modport);
1525	
1526	}
