1528	AstNode * AST::find_modport(AstNode *intf, std::string name)
1529	{
1530		for (auto &ch : intf->children)
1531			if (ch->type == AST_MODPORT)
1532				if (ch->str == name) // Modport found
1533					return ch.get();
1534		return NULL;
1535	}
