1537	// Iterate over all wires in an interface and add them as wires in the AST module:
1538	void AST::explode_interface_port(AstNode *module_ast, RTLIL::Module * intfmodule, std::string intfname, AstNode *modport)
1539	{
1540		for (auto w : intfmodule->wires()){
1541			auto loc = module_ast->location;
1542			auto wire = std::make_unique<AstNode>(loc, AST_WIRE, std::make_unique<AstNode>(loc, AST_RANGE, AstNode::mkconst_int(loc, w->width -1, true), AstNode::mkconst_int(loc, 0, true)));
1543			std::string origname = w->name.unescape();
1544			std::string newname = intfname + "." + origname;
1545			wire->str = newname;
1546			if (modport != NULL) {
1547				bool found_in_modport = false;
1548				// Search for the current wire in the wire list for the current modport
1549				for (auto &ch : modport->children) {
1550					if (ch->type == AST_MODPORTMEMBER) {
1551						std::string compare_name = "\\" + origname;
1552						if (ch->str == compare_name) { // Found signal. The modport decides whether it is input or output
1553							found_in_modport = true;
1554							wire->is_input = ch->is_input;
1555							wire->is_output = ch->is_output;
1556							break;
1557						}
1558					}
1559				}
1560				if (found_in_modport) {
1561					module_ast->children.push_back(std::move(wire));
1562				}
1563			}
1564			else { // If no modport, set inout
1565				wire->is_input = true;
1566				wire->is_output = true;
1567				module_ast->children.push_back(std::move(wire));
1568			}
1569		}
1570	}
