1572	// AstModules may contain cells marked with ID::reprocess_after, which indicates
1573	// that it should be reprocessed once the specified module has been elaborated.
1574	bool AstModule::reprocess_if_necessary(RTLIL::Design *design)
1575	{
1576		for (const RTLIL::Cell *cell : cells())
1577		{
1578			std::string modname = cell->get_string_attribute(ID::reprocess_after);
1579			if (modname.empty())
1580				continue;
1581			if (design->module(modname) || design->module("$abstract" + modname)) {
1582				log("Reprocessing module %s because instantiated module %s has become available.\n",
1583						name.unescape(), RTLIL::unescape_id(modname));
1584				loadconfig();
1585				process_and_replace_module(design, this, ast.get(), NULL);
1586				return true;
1587			}
1588		}
1589		return false;
1590	}
