1592	// When an interface instance is found in a module, the whole RTLIL for the module will be rederived again
1593	// from AST. The interface members are copied into the AST module with the prefix of the interface.
1594	void AstModule::expand_interfaces(RTLIL::Design *design, const dict<RTLIL::IdString, RTLIL::Module*> &local_interfaces)
1595	{
1596		loadconfig();
1597	
1598		auto new_ast = ast->clone();
1599		auto loc = ast->location;
1600		for (auto &intf : local_interfaces) {
1601			std::string intfname = intf.first.str();
1602			RTLIL::Module *intfmodule = intf.second;
1603			for (auto w : intfmodule->wires()){
1604				auto wire = std::make_unique<AstNode>(loc, AST_WIRE, std::make_unique<AstNode>(loc, AST_RANGE, AstNode::mkconst_int(loc, w->width -1, true), AstNode::mkconst_int(loc, 0, true)));
1605				std::string newname = w->name.unescape();
1606				newname = intfname + "." + newname;
1607				wire->str = newname;
1608				new_ast->children.push_back(std::move(wire));
1609			}
1610		}
1611	
1612		auto ast_before_replacing_interface_ports = new_ast->clone();
1613	
1614		// Explode all interface ports. Note this will only have an effect on 'top
1615		// level' modules. Other sub-modules will have their interface ports
1616		// exploded via the derive(..) function
1617		for (size_t i =0; i<new_ast->children.size(); i++)
1618		{
1619			const auto& ch2 = new_ast->children[i];
1620			if (ch2->type == AST_INTERFACEPORT) { // Is an interface port
1621				std::string name_port = ch2->str; // Name of the interface port
1622				if (ch2->children.size() > 0) {
1623					for(size_t j=0; j<ch2->children.size();j++) {
1624						const auto& ch = ch2->children[j];
1625						if(ch->type == AST_INTERFACEPORTTYPE) { // Found the AST node containing the type of the interface
1626							std::pair<std::string,std::string> res = split_modport_from_type(ch->str);
1627							std::string interface_type = res.first;
1628							std::string interface_modport = res.second; // Is "", if no modport
1629							if (design->module(interface_type) != nullptr) {
1630								// Add a cell to the module corresponding to the interface port such that
1631								// it can further propagated down if needed:
1632								auto celltype_for_intf = std::make_unique<AstNode>(loc, AST_CELLTYPE);
1633								celltype_for_intf->str = interface_type;
1634								auto cell_for_intf = std::make_unique<AstNode>(loc, AST_CELL, std::move(celltype_for_intf));
1635								cell_for_intf->str = name_port + "_inst_from_top_dummy";
1636								new_ast->children.push_back(std::move(cell_for_intf));
1637	
1638								// Get all members of this non-overridden dummy interface instance:
1639								RTLIL::Module *intfmodule = design->module(interface_type); // All interfaces should at this point in time (assuming
1640								                                                              // reprocess_module is called from the hierarchy pass) be
1641								                                                              // present in design->modules_
1642								AstModule *ast_module_of_interface = (AstModule*)intfmodule;
1643								std::string interface_modport_compare_str = "\\" + interface_modport;
1644								AstNode *modport = find_modport(ast_module_of_interface->ast.get(), interface_modport_compare_str); // modport == NULL if no modport
1645								// Iterate over all wires in the interface and add them to the module:
1646								explode_interface_port(new_ast.get(), intfmodule, name_port, modport);
1647							}
1648							break;
1649						}
1650					}
1651				}
1652			}
1653		}
1654	
1655		// Generate RTLIL from AST for the new module and add to the design,
1656		// renaming this module to move it out of the way.
1657		RTLIL::Module* new_module =
1658			process_and_replace_module(design, this, new_ast.get(), std::move(ast_before_replacing_interface_ports));
1659	
1660		// Set the attribute "interfaces_replaced_in_module" so that it does not happen again.
1661		new_module->set_bool_attribute(ID::interfaces_replaced_in_module);
1662	}
1663	
1664	// create a new parametric module (when needed) and return the name of the generated module - WITH support for interfaces
1665	// This method is used to explode the interface when the interface is a port of the module (not instantiated inside)
1666	RTLIL::IdString AstModule::derive(RTLIL::Design *design, const dict<RTLIL::IdString, RTLIL::Const> &parameters, const dict<RTLIL::IdString, RTLIL::Module*> &interfaces, const dict<RTLIL::IdString, RTLIL::IdString> &modports, bool /*mayfail*/)
1667	{
1668		std::unique_ptr<AstNode> new_ast = NULL;
1669		std::string modname = derive_common(design, parameters, &new_ast);
1670	
1671		// Since interfaces themselves may be instantiated with different parameters,
1672		// "modname" must also take those into account, so that unique modules
1673		// are derived for any variant of interface connections:
1674		std::string interf_info = "";
1675	
1676		bool has_interfaces = false;
1677		for(auto &intf : interfaces) {
1678			interf_info += intf.second->name.unescape();
1679			has_interfaces = true;
1680		}
1681	
1682		std::string new_modname = modname;
1683		if (has_interfaces)
1684			new_modname += "$interfaces$" + interf_info;
1685	
1686	
1687		if (!design->has(new_modname)) {
1688			if (!new_ast) {
1689				auto mod = dynamic_cast<AstModule*>(design->module(modname));
1690				new_ast = mod->ast->clone();
1691			}
1692			modname = new_modname;
1693			new_ast->str = modname;
1694	
1695			// Iterate over all interfaces which are ports in this module:
1696			for(auto &intf : interfaces) {
1697				RTLIL::Module * intfmodule = intf.second;
1698				std::string intfname = intf.first.str();
1699				// Check if a modport applies for the interface port:
1700				AstNode *modport = NULL;
1701				if (modports.count(intfname) > 0) {
1702					std::string interface_modport = modports.at(intfname).str();
1703					AstModule *ast_module_of_interface = (AstModule*)intfmodule;
1704					AstNode *ast_node_of_interface = ast_module_of_interface->ast.get();
1705					modport = find_modport(ast_node_of_interface, interface_modport);
1706				}
1707				// Iterate over all wires in the interface and add them to the module:
1708				explode_interface_port(new_ast.get(), intfmodule, intfname, modport);
1709			}
1710	
1711			process_module(design, new_ast.get(), false);
1712			design->module(modname)->check();
1713	
1714			RTLIL::Module* mod = design->module(modname);
1715	
1716			// Now that the interfaces have been exploded, we can delete the dummy port related to every interface.
1717			for(auto &intf : interfaces) {
1718				if(mod->wire(intf.first) != nullptr) {
1719					// Normally, removing wires would be batched together as it's an
1720					//   expensive operation, however, in this case doing so would mean
1721					//   that a cell with the same name cannot be created (below)...
1722					// Since we won't expect many interfaces to exist in a module,
1723					//   we can let this slide...
1724					pool<RTLIL::Wire*> to_remove;
1725					to_remove.insert(mod->wire(intf.first));
1726					mod->remove(to_remove);
1727					mod->fixup_ports();
1728					// We copy the cell of the interface to the sub-module such that it
1729					//   can further be found if it is propagated down to sub-sub-modules etc.
1730					RTLIL::Cell *new_subcell = mod->addCell(intf.first, intf.second->name);
1731					new_subcell->set_bool_attribute(ID::is_interface);
1732				}
1733				else {
1734					log_error("No port with matching name found (%s) in %s. Stopping\n", intf.first, modname);
1735				}
1736			}
1737	
1738			// If any interfaces were replaced, set the attribute 'interfaces_replaced_in_module':
1739			if (interfaces.size() > 0) {
1740				mod->set_bool_attribute(ID::interfaces_replaced_in_module);
1741			}
1742	
1743		} else {
1744			modname = new_modname;
1745			log("Found cached RTLIL representation for module `%s'.\n", modname);
1746		}
1747	
1748		return modname;
1749	}
