1751	// create a new parametric module (when needed) and return the name of the generated module - without support for interfaces
1752	RTLIL::IdString AstModule::derive(RTLIL::Design *design, const dict<RTLIL::IdString, RTLIL::Const> &parameters, bool /*mayfail*/)
1753	{
1754		bool quiet = lib || attributes.count(ID::blackbox) || attributes.count(ID::whitebox);
1755	
1756		std::unique_ptr<AstNode> new_ast = NULL;
1757		std::string modname = derive_common(design, parameters, &new_ast, quiet);
1758	
1759		if (!design->has(modname) && new_ast) {
1760			new_ast->str = modname;
1761			process_module(design, new_ast.get(), false, NULL, quiet);
1762			design->module(modname)->check();
1763		} else if (!quiet) {
1764			log("Found cached RTLIL representation for module `%s'.\n", modname);
1765		}
1766	
1767		return modname;
1768	}
