1770	static std::string serialize_param_value(const RTLIL::Const &val) {
1771		std::string res;
1772		if (val.flags & RTLIL::ConstFlags::CONST_FLAG_STRING)
1773			res.push_back('t');
1774		if (val.flags & RTLIL::ConstFlags::CONST_FLAG_SIGNED)
1775			res.push_back('s');
1776		if (val.flags & RTLIL::ConstFlags::CONST_FLAG_REAL)
1777			res.push_back('r');
1778		if (val.flags & RTLIL::ConstFlags::CONST_FLAG_UNSIZED)
1779			res.push_back('u');
1780		else
1781			res += stringf("%d", GetSize(val));
1782		res.push_back('\'');
1783		res.append(val.as_string("?"));
1784		return res;
1785	}
1786	
1787	std::string AST::derived_module_name(std::string stripped_name, const std::vector<std::pair<RTLIL::IdString, RTLIL::Const>> &parameters) {
1788		std::string para_info;
1789		for (const auto &elem : parameters)
1790			para_info += stringf("%s=%s", elem.first, serialize_param_value(elem.second));
1791	
1792		if (para_info.size() > 60)
1793			return "$paramod$" + sha1(para_info) + stripped_name;
1794		else
1795			return "$paramod" + stripped_name + para_info;
1796	}
1797	
1798	// create a new parametric module (when needed) and return the name of the generated module
1799	std::string AstModule::derive_common(RTLIL::Design *design, const dict<RTLIL::IdString, RTLIL::Const> &parameters, std::unique_ptr<AstNode>* new_ast_out, bool quiet)
1800	{
1801		std::string stripped_name = name.str();
1802		(*new_ast_out) = nullptr;
1803	
1804		if (stripped_name.compare(0, 9, "$abstract") == 0)
1805			stripped_name = stripped_name.substr(9);
1806	
1807		int para_counter = 0;
1808		std::vector<std::pair<RTLIL::IdString, RTLIL::Const>> named_parameters;
1809		for (const auto& child : ast->children) {
1810			if (child->type != AST_PARAMETER)
1811				continue;
1812			para_counter++;
1813			auto it = parameters.find(child->str);
1814			if (it != parameters.end()) {
1815				if (!quiet)
1816					log("Parameter %s = %s\n", child->str, log_signal(it->second));
1817				named_parameters.emplace_back(child->str, it->second);
1818				continue;
1819			}
1820			it = parameters.find(stringf("$%d", para_counter));
1821			if (it != parameters.end()) {
1822				if (!quiet)
1823					log("Parameter %d (%s) = %s\n", para_counter, child->str, log_signal(it->second));
1824				named_parameters.emplace_back(child->str, it->second);
1825				continue;
1826			}
1827		}
1828	
1829		std::string modname = stripped_name;
1830		if (parameters.size()) // not named_parameters to cover hierarchical defparams
1831			modname = derived_module_name(stripped_name, named_parameters);
1832	
1833		if (design->has(modname))
1834			return modname;
1835	
1836		if (!quiet)
1837			log_header(design, "Executing AST frontend in derive mode using pre-parsed AST for module `%s'.\n", stripped_name);
1838		loadconfig();
1839	
1840		pool<IdString> rewritten;
1841		rewritten.reserve(GetSize(parameters));
1842	
1843		auto new_ast = ast->clone();
1844		auto loc = ast->location;
1845		if (!new_ast->attributes.count(ID::hdlname))
1846			new_ast->set_attribute(ID::hdlname, AstNode::mkconst_str(loc, stripped_name.substr(1)));
1847	
1848		para_counter = 0;
1849		for (auto& child : new_ast->children) {
1850			if (child->type != AST_PARAMETER)
1851				continue;
1852			para_counter++;
1853			auto it = parameters.find(child->str);
1854			if (it != parameters.end()) {
1855				if (!quiet)
1856					log("Parameter %s = %s\n", child->str, log_signal(it->second));
1857				goto rewrite_parameter;
1858			}
1859			it = parameters.find(stringf("$%d", para_counter));
1860			if (it != parameters.end()) {
1861				if (!quiet)
1862					log("Parameter %d (%s) = %s\n", para_counter, child->str, log_signal(it->second));
1863				goto rewrite_parameter;
1864			}
1865			continue;
1866		rewrite_parameter:
1867			if (param_has_no_default(child.get()))
1868				child->children.insert(child->children.begin(), nullptr);
1869			if ((it->second.flags & RTLIL::CONST_FLAG_REAL) != 0) {
1870				child->children[0] = std::make_unique<AstNode>(loc, AST_REALVALUE);
1871				child->children[0]->realvalue = std::stod(it->second.decode_string());
1872			} else if ((it->second.flags & RTLIL::CONST_FLAG_STRING) != 0)
1873				child->children[0] = AstNode::mkconst_str(loc, it->second.decode_string());
1874			else
1875				child->children[0] = AstNode::mkconst_bits(loc, it->second.to_bits(), (it->second.flags & RTLIL::CONST_FLAG_SIGNED) != 0, (it->second.flags & RTLIL::CONST_FLAG_UNSIZED) != 0);
1876			rewritten.insert(it->first);
1877		}
1878	
1879		if (GetSize(rewritten) < GetSize(parameters))
1880			for (const auto &param : parameters) {
1881				if (rewritten.count(param.first))
1882					continue;
1883				auto defparam = std::make_unique<AstNode>(loc, AST_DEFPARAM, std::make_unique<AstNode>(loc, AST_IDENTIFIER));
1884				defparam->children[0]->str = param.first.str();
1885				if ((param.second.flags & RTLIL::CONST_FLAG_STRING) != 0)
1886					defparam->children.push_back(AstNode::mkconst_str(loc, param.second.decode_string()));
1887				else
1888					defparam->children.push_back(AstNode::mkconst_bits(loc, param.second.to_bits(), (param.second.flags & RTLIL::CONST_FLAG_SIGNED) != 0));
1889				new_ast->children.push_back(std::move(defparam));
1890			}
1891	
1892		new_ast->fixup_hierarchy_flags(true);
1893		new_ast_out->reset(new_ast.release());
1894		return modname;
1895	}
1896	
1897	RTLIL::Module *AstModule::clone() const
1898	{
1899		AstModule *new_mod = new AstModule;
1900		new_mod->name = name;
1901		cloneInto(new_mod);
1902	
1903		new_mod->ast = ast->clone();
1904		new_mod->nolatches = nolatches;
1905		new_mod->nomeminit = nomeminit;
1906		new_mod->nomem2reg = nomem2reg;
1907		new_mod->mem2reg = mem2reg;
1908		new_mod->noblackbox = noblackbox;
1909		new_mod->lib = lib;
1910		new_mod->nowb = nowb;
1911		new_mod->noopt = noopt;
1912		new_mod->icells = icells;
1913		new_mod->pwires = pwires;
1914		new_mod->autowire = autowire;
1915	
1916		return new_mod;
1917	}
1918	
1919	void AstModule::loadconfig() const
1920	{
1921		current_ast = NULL;
1922		flag_dump_ast1 = false;
1923		flag_dump_ast2 = false;
1924		flag_dump_vlog1 = false;
1925		flag_dump_vlog2 = false;
1926		flag_nolatches = nolatches;
1927		flag_nomeminit = nomeminit;
1928		flag_nomem2reg = nomem2reg;
1929		flag_mem2reg = mem2reg;
1930		flag_noblackbox = noblackbox;
1931		flag_lib = lib;
1932		flag_nowb = nowb;
1933		flag_noopt = noopt;
1934		flag_icells = icells;
1935		flag_pwires = pwires;
1936		flag_autowire = autowire;
1937	}
